// CreateClient create a new LLM client with simple scalar configuration.
//
// This is the primary binding entry-point. All parameters except `api_key`
// are optional — omitting them uses the same defaults as
// [`ClientConfigBuilder`].
//
// Errors are returned when returns [`LiterLlmError`] if the underlying HTTP client cannot be
// constructed, or if the resolved provider configuration is invalid.
func CreateClient(apiKey string, baseURL *string, timeoutSecs *uint64, maxRetries *uint32, modelHint *string) (*DefaultClient, error) {
	capiKey := C.CString(apiKey)
	defer C.free(unsafe.Pointer(capiKey))

	var cBaseURL *C.char
	if baseURL != nil {
		cBaseURL = C.CString(*baseURL)
		defer C.free(unsafe.Pointer(cBaseURL))
	}

	var cTimeoutSecs C.uint64_t = C.uint64_t(^uint64(0))
	if timeoutSecs != nil {
		cTimeoutSecs = C.uint64_t(uint64(*timeoutSecs))
	}

	var cMaxRetries C.uint32_t = C.uint32_t(^uint32(0))
	if maxRetries != nil {
		cMaxRetries = C.uint32_t(uint32(*maxRetries))
	}

	var cModelHint *C.char
	if modelHint != nil {
		cModelHint = C.CString(*modelHint)
		defer C.free(unsafe.Pointer(cModelHint))
	}

	ptr := C.literllm_create_client(capiKey, cBaseURL, cTimeoutSecs, cMaxRetries, cModelHint)
	if err := lastError(); err != nil {
		if ptr != nil {
			C.literllm_default_client_free(ptr)
		}
		return nil, err
	}
	return &DefaultClient{ptr: unsafe.Pointer(ptr)}, nil
}

// CreateClientFromJSON create a new LLM client from a JSON string.
//
// The JSON object accepts the same fields as `liter-llm.toml` (snake_case).
//
// Errors are returned when returns [`LiterLlmError::BadRequest`] if `json` is not valid JSON or
// contains unknown fields.
func CreateClientFromJSON(json string) (*DefaultClient, error) {
	cjson := C.CString(json)
	defer C.free(unsafe.Pointer(cjson))

	ptr := C.literllm_create_client_from_json(cjson)
	if err := lastError(); err != nil {
		if ptr != nil {
			C.literllm_default_client_free(ptr)
		}
		return nil, err
	}
	return &DefaultClient{ptr: unsafe.Pointer(ptr)}, nil
}

// EncodeDataURL encode bytes as a base64 data URL: `data:<mime>;base64,<b64>`.
//
// `mime` defaults to [`IMAGE_PNG`] when `None`.
//
// Example:
//
//	let url = encode_data_url(b"\x89PNG", Some(IMAGE_PNG));
//	assert!(url.starts_with("data:image/png;base64,"));
//
//	let url_default = encode_data_url(b"\x89PNG", None);
//	assert!(url_default.starts_with("data:image/png;base64,"));
//
//	let jpeg_url = encode_data_url(b"\xff\xd8\xff", Some(IMAGE_JPEG));
//	assert!(jpeg_url.starts_with("data:image/jpeg;base64,"));
func EncodeDataURL(bytes []byte, mime *string) string {
	var cBytes *C.uint8_t
	if len(bytes) > 0 {
		var cBytesPinner runtime.Pinner
		cBytesPinner.Pin(&bytes[0])
		defer cBytesPinner.Unpin()
		cBytes = (*C.uint8_t)(unsafe.Pointer(&bytes[0]))
	}
	cBytesLen := C.uintptr_t(len(bytes))

	var cMime *C.char
	if mime != nil {
		cMime = C.CString(*mime)
		defer C.free(unsafe.Pointer(cMime))
	}

	ptr := C.literllm_encode_data_url(cBytes, cBytesLen, cMime)
	defer C.literllm_free_string(ptr)
	return C.GoString(ptr)
}

// DecodeDataURL decode a base64 data URL into [`DecodedDataUrl`].
//
// Returns `None` for:
// - Non-data URLs (strings that do not start with `"data:"`).
// - Malformed prefixes (missing `";base64,"` marker).
// - Invalid base64 payloads.
//
// The returned MIME string is extracted verbatim from the URL prefix —
// it is not validated or normalised.
//
// Example:
//
//	let url = encode_data_url(b"hello", Some(IMAGE_PNG));
//	let decoded = decode_data_url(&url)/* error: valid data URL");
//	assert_eq!(decoded.mime, IMAGE_PNG);
//	assert_eq!(decoded.data, b"hello");
//
//	// Non-data URLs return None.
//	assert!(decode_data_url("https://example.com/img.png").is_none());
//
//	// Missing ;base64, marker returns None.
//	assert!(decode_data_url("data:image/png,plaintext").is_none());
func DecodeDataURL(url string) *DecodedDataURL {
	curl := C.CString(url)
	defer C.free(unsafe.Pointer(curl))

	ptr := C.literllm_decode_data_url(curl)
	return func() *DecodedDataURL {
		jsonPtr := C.literllm_decoded_data_url_to_json(ptr)
		if jsonPtr == nil {
			return nil
		}
		defer C.literllm_free_string(jsonPtr)
		var result DecodedDataURL
		if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
			return nil
		}
		return &result
	}()
}

// RegisterCustomProvider register a custom provider in the global runtime registry.
//
// The provider will be checked **before** all built-in providers during model
// detection. If a provider with the same `name` already exists it is replaced.
//
// Errors are returned when returns an error if the config is invalid (empty name, empty base_url, or
// no model prefixes).
func RegisterCustomProvider(config CustomProviderConfig) error {
	jsonBytescConfig, err := json.Marshal(config)
	if err != nil {
		return fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescConfig) == "null" {
		jsonBytescConfig = []byte("{}")
	}
	tmpStrcConfig := C.CString(string(jsonBytescConfig))
	cConfig := C.literllm_custom_provider_config_from_json(tmpStrcConfig)
	C.free(unsafe.Pointer(tmpStrcConfig))
	if cConfig == nil {
		return fmt.Errorf("failed to create custom_provider_config: %s", C.GoString(C.literllm_last_error_context()))
	}
	defer C.literllm_custom_provider_config_free(cConfig)

	C.literllm_register_custom_provider(cConfig)
	return lastError()
}

// UnregisterCustomProvider remove a previously registered custom provider by name.
//
// Returns `true` if a provider with the given name was found and removed,
// `false` if no such provider existed.
//
// Errors are returned when returns an error if the custom-provider registry cannot be updated.
func UnregisterCustomProvider(name string) (bool, error) {
	cName := C.CString(name)
	defer C.free(unsafe.Pointer(cName))

	ptr := C.literllm_unregister_custom_provider(cName)
	if err := lastError(); err != nil {
		return false, err
	}
	return ptr != 0, nil
}

// Capabilities return the capability flags for a named provider.
//
// Performs an O(n) linear scan over the embedded registry (163 entries).
// Returns an owned value so bindings can pass capability data without
// borrowing registry internals.
//
// For unknown `provider_name` values the function returns an all-`false`
// sentinel so callers never need to handle `Option`.
func Capabilities(providerName string) *ProviderCapabilities {
	cProviderName := C.CString(providerName)
	defer C.free(unsafe.Pointer(cProviderName))

	ptr := C.literllm_capabilities(cProviderName)
	defer C.literllm_provider_capabilities_free(ptr)
	return func() *ProviderCapabilities {
		jsonPtr := C.literllm_provider_capabilities_to_json(ptr)
		if jsonPtr == nil {
			return nil
		}
		defer C.literllm_free_string(jsonPtr)
		var result ProviderCapabilities
		if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
			return nil
		}
		return &result
	}()
}

// AllProviders return all provider configs from the registry.
//
// Useful for tooling, documentation generation, or runtime enumeration.
// Returns the public [`ProviderConfig`] slice (without capability flags).
// To query capability flags for a specific provider use [`capabilities`].
func AllProviders() ([]ProviderConfig, error) {
	ptr := C.literllm_all_providers()
	if err := lastError(); err != nil {
		return nil, err
	}
	if ptr == nil {
		return nil, fmt.Errorf("failed to get result")
	}
	defer C.literllm_free_string(ptr)
	var result []ProviderConfig
	if err := json.Unmarshal([]byte(C.GoString(ptr)), &result); err != nil {
		return nil, fmt.Errorf("failed to unmarshal: %w", err)
	}
	return result, nil
}

// ComplexProviderNames return the set of complex provider names.
//
// Complex providers require custom auth/routing logic beyond simple bearer
// tokens (e.g. AWS Bedrock SigV4, Vertex AI OAuth2).
//
// The returned reference points into the static registry — no allocation.
func ComplexProviderNames() ([]string, error) {
	ptr := C.literllm_complex_provider_names()
	if err := lastError(); err != nil {
		return nil, err
	}
	if ptr == nil {
		return nil, fmt.Errorf("failed to get result")
	}
	defer C.literllm_free_string(ptr)
	var result []string
	if err := json.Unmarshal([]byte(C.GoString(ptr)), &result); err != nil {
		return nil, fmt.Errorf("failed to unmarshal: %w", err)
	}
	return result, nil
}

// CompletionCost calculate the estimated cost of a completion given a model name and token
// counts.
//
// Returns `None` if the model is not present in the embedded pricing registry.
// Returns `Some(cost_usd)` otherwise, where the value is in US dollars.
//
// When an exact model name match is not found, progressively shorter prefixes
// are tried by stripping from the last `-` or `.` separator.  For example,
// `gpt-4-0613` will match `gpt-4` if no `gpt-4-0613` entry exists.
//
// Example:
//
//	let usd = cost::completion_cost("gpt-4o", 1_000, 500)/* error: gpt-4o is a known model");
//	// 1000 * 0.0000025 + 500 * 0.00001 = 0.0025 + 0.005 = 0.0075
//	assert!((usd - 0.0075).abs() < 1e-9);
func CompletionCost(model string, promptTokens uint64, completionTokens uint64) *float64 {
	cModel := C.CString(model)
	defer C.free(unsafe.Pointer(cModel))

	cPromptTokens := C.uint64_t(uint64(promptTokens))

	cCompletionTokens := C.uint64_t(uint64(completionTokens))

	ptr := C.literllm_completion_cost(cModel, cPromptTokens, cCompletionTokens)
	return func() *float64 { v := float64(ptr); return &v }()
}

// CompletionCostWithCache calculate the estimated cost of a completion, accounting for cached
// (cache-hit) prompt tokens billed at the provider's discounted rate.
//
// `cached_tokens` is the count of prompt tokens served from the provider's
// prompt cache. It must be `<= prompt_tokens` (cached tokens are a subset of
// the prompt). The non-cached portion is billed at `input_cost_per_token`
// and the cached portion at `cache_read_input_token_cost` when the model
// has cache pricing; otherwise the entire prompt is billed at the regular
// input rate.
//
// Returns `None` if the model is not present in the embedded pricing
// registry, mirroring [`completion_cost`].
//
// When the model has [`ModelPricing::tiers`], the tier whose
// `min_context_tokens` is the highest value `<= prompt_tokens` supplies the
// input/output/cache rates for the whole call; models without tiers (or
// when `prompt_tokens` is below every tier threshold) use the base rates
// unchanged, matching the original flat-rate behaviour.
