// RefreshCatalog refresh the runtime catalog overlay per `config`.
//
// - `config.enabled == false`: returns `Ok(`[`RefreshOutcome::Disabled`]`)`
// immediately. No network, filesystem, or overlay activity.
// - A fresh on-disk cache (age < `config.ttl_seconds`) exists at the
// resolved cache path (`config.cache_path`, or a default under
// `std::env::temp_dir()`): read + flatten it and install the overlay,
// returning `Ok(`[`RefreshOutcome::FromCache`]`)`. No network request is
// made.
// - Otherwise: validate `config.source_url` uses `https`
// ([`CatalogRefreshError::InsecureUrl`] otherwise), fetch it, flatten it,
// install the overlay, best-effort write the raw JSON to the cache path
// (a cache write failure does not fail the refresh), and return
// `Ok(`[`RefreshOutcome::Fetched`]`)`.
//
// On any error return, the overlay is left untouched: the previously
// active registry (a prior successful overlay, or the embedded catalog if
// none was ever installed) remains in effect. This is what makes the
// feature air-gap-safe — an unreachable or invalid `source_url` never
// degrades `completion_cost` / `model_info` below embedded-catalog
// availability.
func RefreshCatalog(config CatalogRefreshConfig) (*RefreshOutcome, error) {
	jsonBytescConfig, err := json.Marshal(config)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescConfig) == "null" {
		jsonBytescConfig = []byte("{}")
	}
	tmpStrcConfig := C.CString(string(jsonBytescConfig))
	cConfig := C.literllm_catalog_refresh_config_from_json(tmpStrcConfig)
	C.free(unsafe.Pointer(tmpStrcConfig))
	if cConfig == nil {
		return nil, fmt.Errorf("failed to create catalog_refresh_config: %s", C.GoString(C.literllm_last_error_context()))
	}
	defer C.literllm_catalog_refresh_config_free(cConfig)

	ptr := C.literllm_refresh_catalog(cConfig)
	if err := lastError(); err != nil {
		if ptr != nil {
			C.literllm_refresh_outcome_free(ptr)
		}
		return nil, err
	}
	defer C.literllm_refresh_outcome_free(ptr)
	jsonPtr := C.literllm_refresh_outcome_to_json(ptr)
	if jsonPtr == nil {
		return nil, fmt.Errorf("failed to convert to JSON")
	}
	defer C.literllm_free_string(jsonPtr)
	var result RefreshOutcome
	if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
		return nil, fmt.Errorf("failed to unmarshal: %w", err)
	}
	return &result, nil
}

